FUNCTION calculateAmdahlSpeedup(parallel_fraction P, processors N):
 // Theoretical maximum speedup (Amdahl's Law)
 max_speedup = 1 / (1 - P)

 // Actual speedup considering communication overhead
 // overhead = 0.05 * log2(N) for example
 overhead = 0.05 * LOG2(N)
 effective_parallel_time = (P / N) + (1 - P) + overhead
 actual_speedup = 1 / effective_parallel_time

 // Efficiency
 efficiency = actual_speedup / N

 RETURN max_speedup, actual_speedup, efficiency

// Example: P = 0.90 (90% parallelizable), N = 16
// max_speedup = 1/(1-0.9) = 10x
// actual_speedup accounts for overhead
PRINT "Maximum: " + max_speedup + "x"
PRINT "Actual with 16 processors: " + actual_speedup + "x"

from multiprocessing import Pool

def mapper(document):
 """Map phase: Extract words from each document"""
 words = document.lower().split()
 return [(word, 1) for word in words]

def reducer(word_counts):
 """Reduce phase: Aggregate counts for each word"""
 word, counts = word_counts
 return (word, sum(counts))

def map_reduce_wordcount(documents):
 # MAP PHASE: Process each document in parallel
 with Pool(processes=4) as pool:
 map_results = pool.map(mapper, documents)

 # Flatten and group by key
 all_pairs = [pair for doc_pairs in map_results for pair in doc_pairs]
 word_groups = {}
 for word, count in all_pairs:
 if word not in word_groups:
 word_groups[word] = []
 word_groups[word].append(count)

 # REDUCE PHASE: Aggregate in parallel
 with Pool(processes=4) as pool:
 reduce_results = pool.map(reducer, word_groups.items())

 return dict(reduce_results)

# Example usage
docs = [
 "hello world hello",
 "world of parallel computing",
 "hello cloud computing"
]
result = map_reduce_wordcount(docs)
print(result) # {'hello': 3, 'world': 2, ...}

from queue import Queue
from threading import Thread

class Actor:
 def __init__(self):
 self.mailbox = Queue()
 self.state = None
 self.running = True

 def receive(self, message):
 """Process message - override in subclasses"""
 raise NotImplementedError

 def tell(self, message):
 """Send asynchronous message to actor"""
 self.mailbox.put(message)

 def run(self):
 """Actor's event loop - processes messages sequentially"""
 while self.running:
 try:
 message = self.mailbox.get(timeout=1)
 self.receive(message)
 except:
 continue

 def start(self):
 self.thread = Thread(target=self.run)
 self.thread.start()

 def stop(self):
 self.running = False

class CounterActor(Actor):
 def __init__(self):
 super().__init__()
 self.count = 0

 def receive(self, message):
 if message['type'] == 'increment':
 self.count += 1
 print(f"Count: {self.count}")
 elif message['type'] == 'get':
 message['reply_to'].tell({'value': self.count})

# Usage
actor = CounterActor()
actor.start()
actor.tell({'type': 'increment'})
actor.tell({'type': 'increment'})
actor.stop()
